#!/usr/bin/env node

/**
 * Fetch Azure DevOps Work Item #2960
 * Organization: zartis-digital
 * Project: Todo-App (Tadeu Marques)
 */

const { execSync } = require('child_process');

const ORGANIZATION = 'zartis-digital';
const PROJECT = 'Todo-App (Tadeu Marques)';
const WORK_ITEM_ID = 2960;

try {
  console.log(`Fetching work item #${WORK_ITEM_ID}...`);

  const command = `az boards work-item show --id ${WORK_ITEM_ID} --organization https://dev.azure.com/${ORGANIZATION} --output json`;

  const output = execSync(command, { encoding: 'utf-8' });
  const workItem = JSON.parse(output);

  console.log('\n=== WORK ITEM #2960 DETAILS ===\n');
  console.log('ID:', workItem.id);
  console.log('Type:', workItem.fields['System.WorkItemType']);
  console.log('Title:', workItem.fields['System.Title']);
  console.log('State:', workItem.fields['System.State']);
  console.log('Assigned To:', workItem.fields['System.AssignedTo']?.displayName || 'Unassigned');
  console.log('Created Date:', workItem.fields['System.CreatedDate']);
  console.log('Created By:', workItem.fields['System.CreatedBy']?.displayName);
  console.log('\n--- Description ---');
  console.log(workItem.fields['System.Description'] || 'No description');
  console.log('\n--- Acceptance Criteria ---');
  console.log(workItem.fields['Microsoft.VSTS.Common.AcceptanceCriteria'] || 'No acceptance criteria');
  console.log('\n--- Tags ---');
  console.log(workItem.fields['System.Tags'] || 'No tags');
  console.log('\n--- Priority ---');
  console.log(workItem.fields['Microsoft.VSTS.Common.Priority'] || 'Not set');
  console.log('\n--- Story Points ---');
  console.log(workItem.fields['Microsoft.VSTS.Scheduling.StoryPoints'] || 'Not set');

  // Save full JSON for detailed analysis
  require('fs').writeFileSync(
    '/Users/tadeumarques/Coding/tadeu-todo-app/work-item-2960.json',
    JSON.stringify(workItem, null, 2)
  );
  console.log('\n✓ Full work item details saved to work-item-2960.json');

} catch (error) {
  console.error('Error fetching work item:', error.message);
  process.exit(1);
}

